-- Sharding example: PostgreSQL with application-level sharding

-- 1. Create shard databases
CREATE DATABASE shard_0;
CREATE DATABASE shard_1;
CREATE DATABASE shard_2;
CREATE DATABASE shard_3;

-- 2. Create table on each shard
-- (Run on each shard database)
CREATE TABLE users (
    user_id INTEGER PRIMARY KEY,
    username VARCHAR(50) NOT NULL,
    email VARCHAR(255) UNIQUE NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE orders (
    order_id SERIAL PRIMARY KEY,
    user_id INTEGER NOT NULL,
    order_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    total DECIMAL(10, 2),
    status VARCHAR(20) DEFAULT 'pending'
);

CREATE INDEX idx_orders_user ON orders(user_id);

-- 3. Python shard manager
import psycopg2
import hashlib
from typing import Dict, List, Any

class ShardManager:
    def __init__(self, shard_configs: List[Dict]):
        self.shards = {}
        for config in shard_configs:
            shard_id = config['id']
            self.shards[shard_id] = psycopg2.connect(
                host=config['host'],
                database=config['database'],
                user=config['user'],
                password=config['password']
            )

    def _get_shard_id(self, user_id: int) -> str:
        hash_value = int(hashlib.md5(str(user_id).encode()).hexdigest(), 16)
        shard_num = hash_value % len(self.shards)
        return f'shard_{shard_num}'

    def get_connection(self, user_id: int):
        shard_id = self._get_shard_id(user_id)
        return self.shards[shard_id]

    def execute_on_shard(self, user_id: int, query: str, params: tuple = None):
        conn = self.get_connection(user_id)
        cur = conn.cursor()
        cur.execute(query, params)
        conn.commit()
        return cur.fetchall()

    def scatter_gather(self, query: str, params: tuple = None) -> List[Any]:
        results = []
        for shard_id, conn in self.shards.items():
            cur = conn.cursor()
            cur.execute(query, params)
            results.extend(cur.fetchall())
        return results

    def close(self):
        for conn in self.shards.values():
            conn.close()

# 4. Usage example
shard_configs = [
    {'id': 'shard_0', 'host': 'localhost', 'database': 'shard_0', 'user': 'admin', 'password': 'pass'},
    {'id': 'shard_1', 'host': 'localhost', 'database': 'shard_1', 'user': 'admin', 'password': 'pass'},
    {'id': 'shard_2', 'host': 'localhost', 'database': 'shard_2', 'user': 'admin', 'password': 'pass'},
    {'id': 'shard_3', 'host': 'localhost', 'database': 'shard_3', 'user': 'admin', 'password': 'pass'},
]

manager = ShardManager(shard_configs)

# Insert user to correct shard
manager.execute_on_shard(
    user_id=1001,
    query='INSERT INTO users (user_id, username, email) VALUES (%s, %s, %s)',
    params=(1001, 'alice', 'alice@example.com')
)

# Query specific shard
result = manager.execute_on_shard(
    user_id=1001,
    query='SELECT * FROM users WHERE user_id = %s',
    params=(1001,)
)
print(f"Found user on shard: {result}")

# Scatter-gather: Get all premium users
premium_users = manager.scatter_gather(
    'SELECT username, email FROM users WHERE tier = %s',
    ('premium',)
)
print(f"Total premium users: {len(premium_users)}")

